CREATE OR REPLACE FUNCTION public.fn_orderregel_update_voorraad()
RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER AS $$
DECLARE
    v_volgnummer integer;
    v_actor      uuid;
BEGIN
    SELECT volgnummer INTO v_volgnummer FROM public.orders
    WHERE id = NEW.order_id AND status = 'bevestigd';
    IF v_volgnummer IS NULL THEN RETURN NEW; END IF;

    -- Actor: modifiedby als die er is, anders createdby
    v_actor := COALESCE(NEW.modifiedby, NEW.createdby);

    -- Geval 1: Soft delete
    IF OLD.deletedon IS NULL AND NEW.deletedon IS NOT NULL THEN
        INSERT INTO public.voorraad_mutaties
            (product_id, order_id, type, aantal, opmerking, createdby)
        VALUES (NEW.product_id, NEW.order_id,
                'in'::public.voorraad_mutatie_type, NEW.aantal,
                'Automatisch teruggeBoekt bij verwijdering uit bevestigde order #' || v_volgnummer,
                v_actor);
        RETURN NEW;
    END IF;

    -- Geval 2: Soft restore
    IF OLD.deletedon IS NOT NULL AND NEW.deletedon IS NULL THEN
        INSERT INTO public.voorraad_mutaties
            (product_id, order_id, type, aantal, opmerking, createdby)
        VALUES (NEW.product_id, NEW.order_id,
                'uit'::public.voorraad_mutatie_type, -NEW.aantal,
                'Automatisch afgeboekt bij herstel van bevestigde order #' || v_volgnummer,
                v_actor);
        RETURN NEW;
    END IF;

    -- Geval 3: Aantalwijziging
    IF NEW.deletedon IS NULL AND NEW.aantal <> OLD.aantal THEN
        INSERT INTO public.voorraad_mutaties
            (product_id, order_id, type, aantal, opmerking, createdby)
        VALUES (NEW.product_id, NEW.order_id,
                'correctie'::public.voorraad_mutatie_type,
                -(NEW.aantal - OLD.aantal),
                'Correctie bij aantalwijziging op bevestigde order #' || v_volgnummer
                    || ' (' || OLD.aantal || ' → ' || NEW.aantal || ')',
                v_actor);
        RETURN NEW;
    END IF;

    RETURN NEW;
END; $$
